import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How do I calculate square footage of a room?", a: "Multiply the length of the room by its width. Example: a room that is 15 feet long and 12 feet wide = 15  x  12 = 180 square feet. For irregularly shaped rooms, divide the room into rectangles, calculate each section separately, and add them together." },
  { q: "How do I calculate square footage of an L-shaped room?", a: "Divide the L-shape into two non-overlapping rectangles. Measure each rectangle's length and width, calculate the area of each (L  x  W), then add both areas together. Example: L-room = 12 x 10 section + 8 x 6 section = 120 + 48 = 168 square feet." },
  { q: "How many square feet is a 10x10 room?", a: "A 10 x 10 room = 100 square feet. This is the standard reference size for small storage units and small bedrooms. For context: 200 sq ft is a small apartment studio, 500 sq ft is a one-bedroom apartment, 2,000 sq ft is a typical single-family home." },
  { q: "How do I convert square feet to square meters?", a: "Multiply square feet by 0.0929. Example: 500 sq ft x 0.0929 = 46.45 sq m. To reverse: multiply sq m by 10.764. Quick mental estimate: 1 sq m = 10.76 sq ft, so divide square feet by about 11 for a rough square meter estimate." },
  { q: "How much paint do I need for a room?", a: "Paint coverage: ~400 square feet per gallon (flat walls). Measure wall area = perimeter  x  wall height. Subtract window and door areas (~20 sq ft per door, ~15 sq ft per window). Divide by 400 for gallons. Add 10% for waste. Most rooms need 2 coats, so multiply by 2." },
  { q: "How do I measure square footage for flooring?", a: "Measure length and width of each area. Add 10% waste factor for rectangular rooms (or 15% for diagonal cuts). Round up to the nearest box (most flooring is sold in boxes covering 20-30 sq ft). For tile: add 10-15% waste for pattern cuts and breakage." },
  { q: "What is the formula for a circle's area?", a: "Area = pi x r squared, where r is the radius (half the diameter). Example: a circular room with 10-foot radius = pi x 10 squared = pi x 100 = 314.16 sq ft. For a diameter of 20 feet, radius = 10 feet. This formula is used for round rooms, ponds, and circular patios." },
  { q: "How many square feet is an acre?", a: "1 acre = 43,560 square feet. A standard football field (including end zones) is about 57,600 sq ft - about 1.32 acres. A square acre would be approximately 209  x  209 feet. Half an acre = 21,780 sq ft. Quarter acre = 10,890 sq ft." },
];

const ROOM_SIZES = [
  ["Small bedroom", "10 x 10 ft", "100 sq ft", "9.3 sq m"],
  ["Standard bedroom", "12 x 12 ft", "144 sq ft", "13.4 sq m"],
  ["Master bedroom", "15 x 18 ft", "270 sq ft", "25.1 sq m"],
  ["Small bathroom", "5 x 8 ft", "40 sq ft", "3.7 sq m"],
  ["Standard bathroom", "8 x 10 ft", "80 sq ft", "7.4 sq m"],
  ["Living room", "15 x 20 ft", "300 sq ft", "27.9 sq m"],
  ["Large living room", "20 x 25 ft", "500 sq ft", "46.5 sq m"],
  ["Two-car garage", "20 x 20 ft", "400 sq ft", "37.2 sq m"],
  ["Studio apartment", "~500 sq ft total", "500 sq ft", "46.5 sq m"],
  ["Typical US home", "~2,300 sq ft total", "2,300 sq ft", "213.7 sq m"],
];

type Shape = "rectangle" | "circle" | "triangle";

export default function SquareFootageCalculator() {
  const [shape, setShape] = useState<Shape>("rectangle");
  const [length, setLength] = useState(15);
  const [width, setWidth] = useState(12);
  const [radius, setRadius] = useState(10);
  const [base, setBase] = useState(20);
  const [height, setHeight] = useState(10);

  const area = shape === "rectangle" ? length * width
    : shape === "circle" ? Math.PI * radius * radius
    : 0.5 * base * height;
  const sqMeters = area * 0.0929;
  const sqYards = area / 9;

  return (
    <>
      <SEOHead
        title="Free Square Footage Calculator Online - Calculate Room Size Instantly | CalcHive"
        description="Free online square footage calculator. Calculate the square footage of any room including rectangles, circles and triangles instantly. 100% free for everyone, no signup required."
        canonical="/square-footage-calculator"
        keywords="free square footage calculator, square footage calculator online free, calculate room square footage free, square feet calculator free, room size calculator free online"
        category="Construction Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-stone-600 dark:text-stone-400 bg-stone-100 dark:bg-stone-800/50 px-3 py-1 rounded-full mb-4 inline-block">Housing</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Square Footage Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free square footage calculator to calculate room square footage free for rectangles, circles, triangles, and common spaces. This square footage calculator online free also works as a square feet calculator free and room size calculator free online.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6">
            <label className="text-sm font-semibold text-foreground mb-2 block">Shape</label>
            <div className="flex gap-2">
              {(["rectangle", "circle", "triangle"] as Shape[]).map(s => (
                <button key={s} onClick={() => setShape(s)} className={`flex-1 py-2 rounded-xl text-sm font-semibold border capitalize transition-all ${shape === s ? "bg-stone-600 text-white border-stone-600" : "bg-card text-muted-foreground border-border hover:border-stone-400"}`}>{s}</button>
              ))}
            </div>
          </div>
          <div className="space-y-6 mb-8">
            {shape === "rectangle" && (<>
              <SliderInput id="length" label="Length (ft)" value={length} min={1} max={200} step={0.5} onChange={setLength} format={v => `${v} ft`} testId="input-length" />
              <SliderInput id="width" label="Width (ft)" value={width} min={1} max={200} step={0.5} onChange={setWidth} format={v => `${v} ft`} testId="input-width" />
            </>)}
            {shape === "circle" && <SliderInput id="radius" label="Radius (ft)" value={radius} min={1} max={100} step={0.5} onChange={setRadius} format={v => `${v} ft (diameter: ${v*2} ft)`} testId="input-radius" />}
            {shape === "triangle" && (<>
              <SliderInput id="base" label="Base (ft)" value={base} min={1} max={200} step={0.5} onChange={setBase} format={v => `${v} ft`} testId="input-base" />
              <SliderInput id="height" label="Height (ft)" value={height} min={1} max={200} step={0.5} onChange={setHeight} format={v => `${v} ft`} testId="input-height" />
            </>)}
          </div>
          <motion.div key={`${shape}-${area}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-stone-600 to-stone-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Square Footage</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-sqft">{area.toFixed(1)}</p>
              <p className="text-white/70 text-sm mt-1">square feet</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {[{ label: "Square Meters", value: sqMeters.toFixed(2) + " sq m" }, { label: "Square Yards", value: sqYards.toFixed(2) + " sq yd" }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Square Footage of Any Room for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Rectangle: Area = Length  x  Width</p>
            <p>Circle:    Area = pi x radius squared (pi = 3.14159)</p>
            <p>Triangle:  Area = 0.5 x Base x Height</p>
            <p className="text-xs text-muted-foreground mt-2">Unit conversions: 1 sq ft = 0.0929 sq m = 0.1111 sq yd</p>
            <p className="text-xs text-muted-foreground">1 sq m = 10.764 sq ft - 1 sq yd = 9 sq ft</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Calculate Square Footage for Rectangles Circles and Triangles</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Room Type", "Typical Dimensions", "Square Feet", "Square Meters"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {ROOM_SIZES.map(([room, dims, sqft, sqm]) => (
                  <tr key={room} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{room}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{dims}</td>
                    <td className="py-2.5 px-4 font-bold text-stone-600 dark:text-stone-400">{sqft}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{sqm}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Room Size Calculator for Homeowners and Contractors</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free construction tool on mobile or desktop to estimate materials quickly, compare project scenarios, and plan with less guesswork.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/square-footage-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


